function s(){const e=document.getElementById("tool-form");e&&e.addEventListener("submit",r=>{r.preventDefault();const t=parseFloat(document.getElementById("valor")?.value||"0"),n=parseFloat(document.getElementById("porcentaje")?.value||"0"),l=t*n/100,o=document.getElementById("result");o&&(o.innerHTML=`<strong>Resultado:</strong> ${n}% de ${t} es ${l.toFixed(2)}`)})}export{s as default};
